export interface MatchData {
  id: string;
  league: string;
  homeTeam: string;
  awayTeam: string;
  date: string;
  impliedOdds?: {
    home: number;
    draw: number;
    away: number;
  };
  formAnalysis?: string;
}

export type MarketType = 'Match Winner' | 'Over/Under' | 'BTTS' | 'Double Chance' | 'Correct Score';

export interface BetLeg {
  matchId: string;
  selection: string; // e.g., "Arsenal Win", "Over 2.5 Goals"
  odds: number;
  modelProbability: number; // 0-100
  edge: number; // Percentage difference between model and implied
  reasoning: string;
  historicalInsight?: string; // New: Key trend from previous seasons
}

export interface ParlayRecommendation {
  id: string;
  legs: BetLeg[];
  totalOdds: number;
  modelWinProbability: number;
  expectedValue: number;
  recommendedStake: number; // Amount
  stakePercentage: number; // % of bankroll
  riskLevel: 'Safe' | 'Medium' | 'Risky';
  confidenceScore: number; // 0-10
  overallReasoning: string;
}

export interface BacktestTrade {
  date: string;
  matchups: string;
  selection: string; // The parlay summary
  odds: number;
  stake: number;
  result: 'WIN' | 'LOSS';
  pnl: number;
  bankrollAfter: number;
  notes: string;
}

export interface BacktestResult {
  period: string;
  startingBankroll: number;
  targetBankroll: number;
  finalBankroll: number;
  totalTrades: number;
  wins: number;
  losses: number;
  roi: number;
  trades: BacktestTrade[];
  analysis: string;
}

export interface StrategyStep {
  stepNumber: number;
  date: string;
  plannedStake: number;
  projectedWin: number;
  parlayRecommendation?: ParlayRecommendation; // If a match is found
  status: 'ready' | 'pending_previous_win' | 'future_placeholder';
  note: string;
}

export interface StrategyPlan {
  createdAt: string;
  startingBankroll: number;
  targetBankroll: number;
  targetOdds: number;
  totalSteps: number;
  steps: StrategyStep[];
  analysis: string;
}

export type AnalysisMode = 'live' | 'backtest' | 'strategy_prep' | 'betslip_of_the_week' | 'one_shot_challenge' | 'one_shot_backtest' | 'correct_score';

export interface UserSettings {
  bankroll: number;
  targetBankroll: number;
  isGlobalScan: boolean; // New: Global search toggle
  selectedLeagues: string[];
  preferredMarkets: MarketType[];
  maxLegs: number;
  targetDate: string;
  targetOdds: number;
  minConfidence: number;
  analysisMode: AnalysisMode;
  backtestDate?: string; // Changed from backtestMonth
}

export type AppState = 'setup' | 'searching' | 'analyzing' | 'results' | 'error' | 'backtesting' | 'backtest_results' | 'strategy_prep' | 'strategy_results' | 'betslip_results';

import { GoogleGenAI } from "@google/genai";
import { MatchData, ParlayRecommendation, UserSettings, BacktestResult, StrategyPlan, StrategyStep } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

const cleanJson = (text: string) => {
  let clean = text.replace(/```json\s*/g, "").replace(/```\s*/g, "");
  const firstSquare = clean.indexOf('[');
  const lastSquare = clean.lastIndexOf(']');
  const firstCurly = clean.indexOf('{');
  const lastCurly = clean.lastIndexOf('}');

  if (firstSquare !== -1 && lastSquare !== -1 && lastSquare > firstSquare) {
      if (firstCurly !== -1 && firstCurly < firstSquare) {
         return clean.substring(firstCurly, lastCurly + 1);
      }
      return clean.substring(firstSquare, lastSquare + 1);
  }
  if (firstCurly !== -1 && lastCurly !== -1 && lastCurly > firstCurly) {
    return clean.substring(firstCurly, lastCurly + 1);
  }
  return clean.trim();
};

const parseAndValidateParlays = (jsonStr: string, settings: UserSettings): ParlayRecommendation[] => {
    try {
        let parsed = JSON.parse(jsonStr);
        if (!Array.isArray(parsed) && !parsed.legs && !parsed.matchId) {
             const values = Object.values(parsed);
             const foundArray = values.find(v => Array.isArray(v));
             if (foundArray) parsed = foundArray;
             else {
                 const foundObject = values.find(v => typeof v === 'object' && v !== null && (v as any).legs);
                 if (foundObject) parsed = foundObject;
             }
        }
        let results: any[] = Array.isArray(parsed) ? parsed : [parsed];
        results = results.map(p => {
             const legs = Array.isArray(p.legs) ? p.legs : [];
             let calculatedOdds = p.totalOdds;
             if (!calculatedOdds || calculatedOdds === 0) {
                 calculatedOdds = legs.reduce((acc: number, leg: any) => acc * (parseFloat(leg.odds) || 1.0), 1.0);
             }
             let stake = p.recommendedStake;
             if (!stake || stake === 0) stake = settings.bankroll;
             let confidence = p.confidenceScore;
             if (confidence === undefined || confidence === null || confidence === 0) confidence = 9.0;

             return {
                 ...p,
                 legs: legs,
                 totalOdds: parseFloat(calculatedOdds || 0),
                 recommendedStake: parseFloat(stake || 0),
                 confidenceScore: parseFloat(confidence || 0),
                 riskLevel: p.riskLevel || 'Medium',
                 expectedValue: parseFloat(p.expectedValue || 0),
                 stakePercentage: p.stakePercentage || 100
             } as ParlayRecommendation;
        });
        return results.filter(p => p.legs.length > 0 || p.totalOdds > 0);
    } catch (e) {
        return [];
    }
};

export const fetchUpcomingMatches = async (settings: UserSettings): Promise<{ matches: MatchData[], rawContext: string }> => {
  try {
    const model = 'gemini-2.5-flash';
    const date = settings.targetDate;
    const dateObj = new Date(date);
    const humanDate = dateObj.toLocaleDateString('en-GB', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });

    const now = new Date();
    const localToday = now.toLocaleDateString('en-CA');
    const isToday = date === localToday;
    const userTime = now.toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit', hour12: false });

    // Use Global Scan logic or specific leagues
    const searchQuery = settings.isGlobalScan 
      ? `Top professional football fixtures and betting odds worldwide for ${humanDate} form stats injuries`
      : settings.selectedLeagues.map(l => `"${l}" fixtures ${humanDate} form stats injuries`).join(" OR ");

    const prompt = `
      You are a World-Class Sports Data Scout.

      TASK: Find the absolute BEST professional football matches for: ${humanDate} (${date}).
      ${settings.isGlobalScan ? "MODE: GLOBAL SCAN (All professional leagues worldwide)" : `MODE: TARGETED (${settings.selectedLeagues.join(", ")})`}
      USER TARGET: $${settings.targetBankroll} from $${settings.bankroll}

      SEARCH QUERY: ${searchQuery}

      INSTRUCTIONS:
      1. **SCAN EVERYTHING**: Find matches with high liquidity (reliable betting data).
      2. **IDENTIFY BANKERS**: Focus on fixtures with clear favorites or predictable outcomes based on RECENT data.
      3. **TIME FILTER**: ${isToday ? `Only include matches STARTING AFTER ${userTime}.` : ''}
      4. **CROSS-COMPETITION FORM**: Check last 5 games in ALL competitions (Leagues, Cups, Europe).
      5. **DATA TO RETRIEVE**:
         - Team names, League, Kickoff Time.
         - Current Market Odds (H/D/A).
         - Injuries/Suspensions from the last 24 hours.
         - Tactical context (e.g., must-win relegation battles, dead-rubber games).

      OUTPUT FORMAT:
      List found matches:
      "CONFIRMED: [Home] vs [Away] - [League] - [Time] - Odds: [H/D/A]
       STATS: [Summary of form, injuries, and WHY this is a 'Banker' candidate]"
    `;

    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: { tools: [{ googleSearch: {} }] },
    });

    const rawText = response.text || "No data found.";

    const formattingPrompt = `
      Extract a list of matches from this text: "${rawText}"
      User target date: ${date} (${humanDate})
      ${isToday ? `Only extract matches starting after ${userTime}.` : ''}

      Return ONLY a JSON array:
      [
        {
          "id": "string",
          "league": "string",
          "homeTeam": "string",
          "awayTeam": "string",
          "date": "${date}",
          "formAnalysis": "Brief explanation of 'Banker' status",
          "impliedOdds": { "home": number, "draw": number, "away": number }
        }
      ]
    `;

    const formatResponse = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: formattingPrompt,
      config: { responseMimeType: 'application/json' }
    });

    let parsedMatches = JSON.parse(cleanJson(formatResponse.text || "[]"));
    if (!Array.isArray(parsedMatches)) parsedMatches = Object.values(parsedMatches).find(v => Array.isArray(v)) || (parsedMatches.homeTeam ? [parsedMatches] : []);

    return { matches: parsedMatches, rawContext: rawText };
  } catch (error) {
    throw new Error("Failed to search for matches.");
  }
};

export const analyzeAndGenerateParlays = async (
  matchesContext: string,
  settings: UserSettings
): Promise<ParlayRecommendation[]> => {
  try {
    const model = 'gemini-3-pro-preview';
    const prompt = `
      You are an Ultra-Conservative Football Investment Analyst.

      STRATEGY: BANKER COMPOUNDING
      Bankroll: $${settings.bankroll}
      Target: $${settings.targetBankroll}
      Target Odds: ${settings.targetOdds}

      TASK: Select the "BEST" matches from the provided list to hit the target.
      If the target bankroll is significantly higher than the start, prioritize a longer list of safer "Double Chance" legs.

      RULES:
      1. **COWARDICE IS A VIRTUE**: Only pick outcomes with >90% probability based on the form/injury data provided.
      2. **MARKET SELECTION**: Use ${settings.preferredMarkets.join(", ")}.
      3. **REASONING**: Cite specific recent form (e.g., "Team A hasn't lost at home in 10 games").

      Context Data:
      ${matchesContext}

      Return a JSON array of 'ParlayRecommendation' objects.
    `;

    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 16000 },
        responseMimeType: 'application/json'
      },
    });

    return parseAndValidateParlays(cleanJson(response.text || "[]"), settings);
  } catch (error) {
    throw new Error("Failed to generate analysis.");
  }
};

export const performBacktest = async (settings: UserSettings): Promise<BacktestResult> => {
  try {
    const model = 'gemini-3-pro-preview';
    const dateToTest = settings.backtestDate || settings.targetDate;
    const dateObj = new Date(dateToTest);
    const humanDate = dateObj.toLocaleDateString('en-GB', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });

    const prompt = `
      Act as a Historical Sports Betting Analyst.

      TASK: Conduct a "Historical Banker Simulation" for exactly ONE DATE: **${humanDate} (${dateToTest})**.
      Leagues: ${settings.isGlobalScan ? "ALL MAJOR LEAGUES" : settings.selectedLeagues.join(", ")}
      Target Odds: ${settings.targetOdds}

      Simulation Logic:
      1. Search for actual results of football matches on ${humanDate}.
      2. Identify the "Best" bets that would have been identified as Bankers pre-match.
      3. Construct a parlay that hits ${settings.targetOdds} odds.
      4. Report if it WON or LOST based on the real scores.

      Return a JSON Object (BacktestResult).
    `;

    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        thinkingConfig: { thinkingBudget: 16000 },
        responseMimeType: 'application/json'
      },
    });

    return JSON.parse(cleanJson(response.text || "{}"));
  } catch (error) {
    throw new Error("Failed to run backtest simulation.");
  }
};

// Re-mapping existing functions to handle settings object correctly
export const generateBetslipOfTheWeek = async (matchesContext: string, settings: UserSettings) => analyzeAndGenerateParlays(matchesContext, settings);
