import React, { useState } from 'react';
import { AVAILABLE_LEAGUES, AVAILABLE_MARKETS } from '../constants';
import { UserSettings, MarketType, AnalysisMode } from '../types';
import { Settings, DollarSign, Globe, ArrowRight, Target, Layers, Calendar, Crosshair, Gauge, History, Zap, Map, ScrollText, Flag, Rocket, Binary } from 'lucide-react';

interface SetupFormProps {
  onComplete: (settings: UserSettings) => void;
}

export const SetupForm: React.FC<SetupFormProps> = ({ onComplete }) => {
  const [analysisMode, setAnalysisMode] = useState<AnalysisMode>('live');
  const [bankroll, setBankroll] = useState<string>('10');
  const [targetBankroll, setTargetBankroll] = useState<string>('1000');
  const [isGlobalScan, setIsGlobalScan] = useState<boolean>(true);
  const [selectedLeagues, setSelectedLeagues] = useState<string[]>(['Premier League', 'La Liga']);
  const [preferredMarkets, setPreferredMarkets] = useState<MarketType[]>(['Double Chance', 'Over/Under']);
  const [maxLegs, setMaxLegs] = useState<number>(3);
  const [targetDate, setTargetDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [backtestDate, setBacktestDate] = useState<string>(new Date(Date.now() - 86400000).toISOString().split('T')[0]);
  const [targetOdds, setTargetOdds] = useState<string>('2.5');
  const [minConfidence, setMinConfidence] = useState<number>(9);

  const toggleLeague = (league: string) => {
    if (selectedLeagues.includes(league)) {
      setSelectedLeagues(selectedLeagues.filter(l => l !== league));
    } else {
      setSelectedLeagues([...selectedLeagues, league]);
    }
  };

  const toggleMarket = (market: MarketType) => {
    if (preferredMarkets.includes(market)) {
      setPreferredMarkets(preferredMarkets.filter(m => m !== market));
    } else {
      setPreferredMarkets([...preferredMarkets, market]);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const amount = parseFloat(bankroll);
    const targetAmount = parseFloat(targetBankroll);
    const odds = (analysisMode === 'one_shot_challenge' || analysisMode === 'one_shot_backtest') ? (targetAmount / amount) : parseFloat(targetOdds);

    if (isNaN(amount) || amount <= 0) return alert("Enter valid bankroll.");
    if (isNaN(targetAmount) || targetAmount <= amount) return alert("Target must be higher than bankroll.");
    if (!isGlobalScan && selectedLeagues.length === 0) return alert("Select at least one league or enable Global Scan.");

    onComplete({ 
      bankroll: amount,
      targetBankroll: targetAmount,
      isGlobalScan,
      selectedLeagues: isGlobalScan ? [] : selectedLeagues, 
      preferredMarkets, 
      maxLegs, 
      targetDate, 
      targetOdds: odds,
      minConfidence,
      analysisMode,
      backtestDate
    });
  };

  return (
    <div className="max-w-3xl mx-auto bg-slate-800 border border-slate-700 rounded-2xl p-8 shadow-2xl">
      <div className="mb-8 text-center">
        <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-blue-600/20 text-blue-400 mb-4">
          <Settings size={32} />
        </div>
        <h2 className="text-3xl font-bold text-white mb-2">SmartBet Engine</h2>
        <p className="text-slate-400">Configure your target and scan depth.</p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-8">

        {/* Mode Toggle */}
        <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-7 bg-slate-900 p-1.5 rounded-xl border border-slate-700 gap-1.5">
          {[
            { id: 'live', icon: <Zap size={16}/>, label: 'Live', color: 'bg-blue-600' },
            { id: 'betslip_of_the_week', icon: <ScrollText size={16}/>, label: 'Week Slip', color: 'bg-amber-600' },
            { id: 'correct_score', icon: <Binary size={16}/>, label: 'Scores', color: 'bg-cyan-600' },
            { id: 'one_shot_challenge', icon: <Rocket size={16}/>, label: 'One Shot', color: 'bg-rose-600' },
            { id: 'strategy_prep', icon: <Map size={16}/>, label: 'Strategy', color: 'bg-emerald-600' },
            { id: 'backtest', icon: <History size={16}/>, label: 'Backtest', color: 'bg-purple-600' },
            { id: 'one_shot_backtest', icon: <History size={16}/>, label: 'Shot Hist', color: 'bg-pink-600' }
          ].map((mode) => (
            <button
              key={mode.id}
              type="button"
              onClick={() => setAnalysisMode(mode.id as AnalysisMode)}
              className={`py-3 px-1 rounded-lg text-[10px] md:text-xs font-bold flex flex-col items-center justify-center gap-2 transition-all ${
                analysisMode === mode.id ? `${mode.color} text-white shadow-lg` : 'text-slate-400 hover:bg-slate-800'
              }`}
            >
              {mode.icon} {mode.label}
            </button>
          ))}
        </div>

        {/* Global Scan Toggle */}
        <div className="bg-slate-900/50 border border-slate-700 rounded-xl p-4 flex items-center justify-between">
           <div className="flex items-center gap-3">
              <div className={`p-2 rounded-lg ${isGlobalScan ? 'bg-blue-600/20 text-blue-400' : 'bg-slate-800 text-slate-500'}`}>
                <Globe size={20} />
              </div>
              <div>
                <div className="font-bold text-white">Global Scan Mode</div>
                <div className="text-xs text-slate-500">Search all major professional leagues for the best bankers.</div>
              </div>
           </div>
           <button 
              type="button"
              onClick={() => setIsGlobalScan(!isGlobalScan)}
