            </label>
            <input
              type="number"
              value={bankroll}
              onChange={(e) => setBankroll(e.target.value)}
              className="w-full bg-slate-900 border border-slate-700 rounded-xl py-3 px-4 text-white font-mono"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-300 mb-3 flex items-center gap-2">
              <Flag size={16} className="text-yellow-400" /> Target Goal
            </label>
            <input
              type="number"
              value={targetBankroll}
              onChange={(e) => setTargetBankroll(e.target.value)}
              className="w-full bg-slate-900 border border-slate-700 rounded-xl py-3 px-4 text-white font-mono"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-300 mb-3 flex items-center gap-2">
              <Crosshair size={16} className="text-red-400" /> Target Odds
            </label>
            <input
              type="number"
              step="0.1"
              value={targetOdds}
              onChange={(e) => setTargetOdds(e.target.value)}
              className="w-full bg-slate-900 border border-slate-700 rounded-xl py-3 px-4 text-white font-mono"
            />
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div>
             <label className="block text-sm font-medium text-slate-300 mb-3 flex items-center gap-2">
              <Calendar size={16} className="text-blue-400" />
              {analysisMode.includes('backtest') ? 'Historical Date' : 'Target Match Date'}
            </label>
            <input
              type="date"
              value={analysisMode.includes('backtest') ? backtestDate : targetDate}
              onChange={(e) => analysisMode.includes('backtest') ? setBacktestDate(e.target.value) : setTargetDate(e.target.value)}
              className="w-full bg-slate-900 border border-slate-700 rounded-xl py-3 px-4 text-white [color-scheme:dark]"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-300 mb-3 flex items-center gap-2">
              <Gauge size={16} className="text-cyan-400" /> Confidence: {minConfidence}
            </label>
            <input 
              type="range" min="1" max="10" value={minConfidence} 
              onChange={(e) => setMinConfidence(parseInt(e.target.value))}
              className="w-full h-2 bg-slate-700 rounded-lg accent-cyan-500"
            />
          </div>
        </div>

        {!isGlobalScan && (
          <div className="animate-in fade-in slide-in-from-top-4 duration-300">
            <label className="block text-sm font-medium text-slate-300 mb-3 flex items-center gap-2">
              <Target size={16} className="text-yellow-400" /> Targeted Leagues
            </label>
            <div className="grid grid-cols-2 md:grid-cols-3 gap-2">
              {AVAILABLE_LEAGUES.map((league) => (
                <button
                  key={league}
                  type="button"
                  onClick={() => toggleLeague(league)}
                  className={`px-3 py-2 rounded-lg text-xs font-medium border transition-all ${
                    selectedLeagues.includes(league) ? 'bg-blue-600 border-blue-500 text-white' : 'bg-slate-900 border-slate-700 text-slate-500'
                  }`}
                >
                  {league}
