import { GoogleGenAI } from "@google/genai";
import { MatchData, ParlayRecommendation, UserSettings, BacktestResult, StrategyPlan } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

const cleanJson = (text: string) => {
  if (!text) return "[]";
  let clean = text.replace(/```json\s*/g, "").replace(/```\s*/g, "");
  const firstSquare = clean.indexOf('[');
  const lastSquare = clean.lastIndexOf(']');
  const firstCurly = clean.indexOf('{');
  const lastCurly = clean.lastIndexOf('}');

  if (firstSquare !== -1 && lastSquare !== -1 && lastSquare > firstSquare) {
      if (firstCurly !== -1 && firstCurly < firstSquare) {
         return clean.substring(firstCurly, lastCurly + 1);
      }
      return clean.substring(firstSquare, lastSquare + 1);
  }
  if (firstCurly !== -1 && lastCurly !== -1 && lastCurly > firstCurly) {
    return clean.substring(firstCurly, lastCurly + 1);
  }
  return clean.trim();
};

const parseAndValidateParlays = (jsonStr: string, settings: UserSettings): ParlayRecommendation[] => {
    try {
        let parsed = JSON.parse(jsonStr);
        // Handle nested arrays or objects returned by different model versions
        if (!Array.isArray(parsed)) {
             const values = Object.values(parsed);
             const foundArray = values.find(v => Array.isArray(v));
             if (foundArray) parsed = foundArray;
             else if (parsed.legs) parsed = [parsed];
             else return [];
        }

        let results: ParlayRecommendation[] = parsed.map((p: any) => {
             const legs = Array.isArray(p.legs) ? p.legs : [];

             // Recalculate odds to ensure they are correct
             const calculatedOdds = legs.reduce((acc: number, leg: any) => acc * (parseFloat(leg.odds) || 1.0), 1.0);

             let stake = parseFloat(p.recommendedStake) || settings.bankroll;
             let confidence = parseFloat(p.confidenceScore) || 8.5;

             return {
                 ...p,
                 id: p.id || Math.random().toString(36).substr(2, 9),
                 legs: legs,
                 totalOdds: parseFloat(calculatedOdds.toFixed(2)),
                 recommendedStake: stake,
                 confidenceScore: confidence,
                 riskLevel: p.riskLevel || 'Medium',
                 expectedValue: parseFloat(p.expectedValue) || 0,
                 stakePercentage: p.stakePercentage || 100,
                 overallReasoning: p.overallReasoning || "Strategy based on team form and historical metrics."
             } as ParlayRecommendation;
        });

        // CRITICAL: Filter out any parlay that doesn't actually have betting legs or valid odds
        return results.filter(p => p.legs && p.legs.length > 0 && p.totalOdds > 1.05);
    } catch (e) {
        console.error("Parsing error:", e);
        return [];
    }
};

export const fetchUpcomingMatches = async (settings: UserSettings): Promise<{ matches: MatchData[], rawContext: string }> => {
  try {
    const model = 'gemini-3-flash-preview';
    const date = settings.targetDate;
    const dateObj = new Date(date);
    const humanDate = dateObj.toLocaleDateString('en-GB', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });

    const now = new Date();
    const userTime = now.toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit', hour12: false });

    const prompt = `
      Search for professional football fixtures on ${humanDate} (${date}).
      Mode: ${settings.isGlobalScan ? "Global Scan - Search ALL professional leagues worldwide (including lower divisions if necessary)" : "Leagues: " + settings.selectedLeagues.join(", ")}

      REQUIREMENTS:
      1. Find at least 5-10 professional matches.
      2. Include kickoff times and current 1X2 betting odds.
      3. For each match, find recent form (W-D-L) for both teams.
      4. Mention any significant injuries or lineup news.

      If it is a major holiday like Dec 25th, search for lower tier English games, international friendlies, or leagues in regions like Turkey, Egypt, or other active territories.
    `;

    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: { tools: [{ googleSearch: {} }] },
    });

    const rawText = response.text || "No match data found.";

    const formattingPrompt = `
      From this raw data, extract a clean list of football matches for ${date}.
      Data: ${rawText}

      Return a JSON array of MatchData objects:
      [{ "id": "uuid", "league": "string", "homeTeam": "string", "awayTeam": "string", "date": "${date}", "formAnalysis": "string", "impliedOdds": { "home": 0, "draw": 0, "away": 0 } }]

      Return an empty array [] if zero professional matches are found.
    `;

    const formatResponse = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: formattingPrompt,
      config: { responseMimeType: 'application/json' }
    });

    let parsedMatches = JSON.parse(cleanJson(formatResponse.text || "[]"));
    if (!Array.isArray(parsedMatches)) {
        parsedMatches = Object.values(parsedMatches).find(v => Array.isArray(v)) || [];
    }

    return { matches: parsedMatches, rawContext: rawText };
  } catch (error) {
    console.error("Fetch error:", error);
    throw new Error("The AI Scout couldn't find matches for this specific date.");
  }
};

