  const handleSetupComplete = async (userSettings: UserSettings) => {
    setSettings(userSettings);
    setError(null);
    setScoutAdvice(null);

    try {
      if (userSettings.analysisMode === 'live' || 
          userSettings.analysisMode === 'betslip_of_the_week' || 
          userSettings.analysisMode === 'one_shot_challenge' || 
          userSettings.analysisMode === 'correct_score') {

        setState('searching');
        const { matches: foundMatches, rawContext } = await fetchUpcomingMatches(userSettings);
        setMatches(foundMatches);

        if (!foundMatches || foundMatches.length === 0) {
          const advice = await getMarketSummary(userSettings);
          setScoutAdvice(advice);
          setState('error');
          return;
        }

        setState('analyzing');
        let recommendations: ParlayRecommendation[] = [];

        switch(userSettings.analysisMode) {
          case 'live': recommendations = await analyzeAndGenerateParlays(rawContext, userSettings); break;
          case 'betslip_of_the_week': recommendations = await generateBetslipOfTheWeek(rawContext, userSettings); break;
          case 'one_shot_challenge': recommendations = await generateOneShotParlay(rawContext, userSettings); break;
          case 'correct_score': recommendations = await generateCorrectScoreTips(rawContext, userSettings); break;
        }

        if (recommendations.length === 0) {
          const advice = await getMarketSummary(userSettings);
          setScoutAdvice(advice);
          setState('error');
          return;
        }

        setParlays(recommendations);
        setState('results');

      } else if (userSettings.analysisMode === 'strategy_prep') {
        setState('searching'); 
        const plan = await generateStrategyPlan(userSettings);
        setStrategyPlan(plan);
        setState('strategy_results');

      } else {
        setState('backtesting');
        const results = userSettings.analysisMode === 'one_shot_backtest' 
          ? await performOneShotBacktest(userSettings)
