const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

const cleanJson = (text: string) => {
  if (!text) return "[]";
  let clean = text.replace(/```json\s*/g, "").replace(/```\s*/g, "");
  const firstSquare = clean.indexOf('[');
  const lastSquare = clean.lastIndexOf(']');
  const firstCurly = clean.indexOf('{');
  const lastCurly = clean.lastIndexOf('}');

  if (firstSquare !== -1 && lastSquare !== -1 && lastSquare > firstSquare) {
      if (firstCurly !== -1 && firstCurly < firstSquare) {
         return clean.substring(firstCurly, lastCurly + 1);
      }
      return clean.substring(firstSquare, lastSquare + 1);
  }
  if (firstCurly !== -1 && lastCurly !== -1 && lastCurly > firstCurly) {
    return clean.substring(firstCurly, lastCurly + 1);
  }
  return clean.trim();
};

export const getMarketSummary = async (settings: UserSettings): Promise<string> => {
  try {
    const model = 'gemini-3-flash-preview';
    const date = settings.targetDate;
    const prompt = `
      The football betting scout found ZERO high-confidence matches for ${date}. 
      Act as a professional sports investment advisor. 
      Explain to the user WHY there might be no good bets today (e.g., international break, major holidays, low-liquidity leagues, or just high-volatility fixtures).
      Encourage a "Smart Skip" or "Rest Day" instead of forced betting.
      Keep it brief, professional, and reassuring.
    `;
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: { tools: [{ googleSearch: {} }] },
    });
    return response.text || "The market is currently quiet. It's often better to skip a day than to force a bet on low-confidence fixtures.";
  } catch (e) {
    return "Football markets are currently experiencing low liquidity or a schedule gap. A disciplined bettor knows when to stay on the sidelines.";
  }
};

const parseAndValidateParlays = (jsonStr: string, settings: UserSettings): ParlayRecommendation[] => {
    try {
        let parsed = JSON.parse(cleanJson(jsonStr));
        if (!Array.isArray(parsed)) {
             const values = Object.values(parsed);
             const foundArray = values.find(v => Array.isArray(v));
             if (foundArray) parsed = foundArray;
             else if (parsed.legs) parsed = [parsed];
             else return [];
        }

        let results: ParlayRecommendation[] = parsed.map((p: any) => {
             const legs = Array.isArray(p.legs) ? p.legs : [];
             const calculatedOdds = legs.reduce((acc: number, leg: any) => acc * (parseFloat(leg.odds) || 1.0), 1.0);
             let stake = parseFloat(p.recommendedStake) || settings.bankroll;
             let confidence = parseFloat(p.confidenceScore) || 8.5;

             return {
                 ...p,
                 id: p.id || Math.random().toString(36).substr(2, 9),
                 legs: legs,
                 totalOdds: parseFloat(calculatedOdds.toFixed(2)),
                 recommendedStake: stake,
                 confidenceScore: confidence,
                 riskLevel: p.riskLevel || 'Medium',
                 expectedValue: parseFloat(p.expectedValue) || 0,
                 stakePercentage: p.stakePercentage || 100,
                 overallReasoning: p.overallReasoning || "Strategy based on team form and historical metrics."
             } as ParlayRecommendation;
        });

        return results.filter(p => p.legs && p.legs.length > 0 && p.totalOdds > 1.05);
    } catch (e) {
        return [];
    }
};

