          );
        })}

        {/* Finish Line */}
         <div className="relative flex flex-col items-center justify-center pt-8 pb-12">
            <div className="w-16 h-16 bg-yellow-500/20 text-yellow-400 rounded-full flex items-center justify-center border-2 border-yellow-500 animate-pulse shadow-[0_0_20px_rgba(234,179,8,0.3)]">
                <Target size={32} />
            </div>
            <div className="mt-4 text-center">
                <div className="text-slate-400 text-sm uppercase tracking-wider font-bold">Target Reached</div>
                <div className="text-3xl font-bold text-yellow-400 font-mono">${plan.targetBankroll}</div>
            </div>
         </div>
      </div>
    </div>
  );
};

import { GoogleGenAI } from "@google/genai";
import { MatchData, ParlayRecommendation, UserSettings, BacktestResult, StrategyPlan, StrategyStep } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

const cleanJson = (text: string) => {
  if (!text) return "[]";
  let clean = text.replace(/```json\s*/g, "").replace(/```\s*/g, "");
  const firstSquare = clean.indexOf('[');
  const lastSquare = clean.lastIndexOf(']');
  const firstCurly = clean.indexOf('{');
  const lastCurly = clean.lastIndexOf('}');

  if (firstSquare !== -1 && lastSquare !== -1 && lastSquare > firstSquare) {
      if (firstCurly !== -1 && firstCurly < firstSquare) {
         return clean.substring(firstCurly, lastCurly + 1);
      }
      return clean.substring(firstSquare, lastSquare + 1);
  }
  if (firstCurly !== -1 && lastCurly !== -1 && lastCurly > firstCurly) {
    return clean.substring(firstCurly, lastCurly + 1);
  }
  return clean.trim();
};

export const getMarketSummary = async (settings: UserSettings): Promise<string> => {
  try {
    const model = 'gemini-3-flash-preview';
    const date = settings.targetDate;
    const prompt = `
      The football betting scout found ZERO high-confidence matches for ${date}. 
      Explain why (holidays, international break, etc.) and encourage a "Smart Skip".
    `;
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: { tools: [{ googleSearch: {} }] },
    });
    return response.text || "The market is currently quiet. Discipline is key.";
  } catch (e) {
    return "Football markets are currently experiencing low liquidity.";
  }
};

const parseAndValidateParlays = (jsonStr: string, settings: UserSettings): ParlayRecommendation[] => {
    try {
        let parsed = JSON.parse(cleanJson(jsonStr));
        if (!Array.isArray(parsed)) {
             const values = Object.values(parsed);
             const foundArray = values.find(v => Array.isArray(v));
             if (foundArray) parsed = foundArray;
             else if (parsed.legs) parsed = [parsed];
             else return [];
        }

        let results: ParlayRecommendation[] = parsed.map((p: any) => {
             const legs = Array.isArray(p.legs) ? p.legs : [];
             const calculatedOdds = legs.reduce((acc: number, leg: any) => acc * (parseFloat(leg.odds) || 1.0), 1.0);
             let stake = parseFloat(p.recommendedStake) || settings.bankroll;

             return {
                 ...p,
                 id: p.id || Math.random().toString(36).substr(2, 9),
                 legs: legs,
                 totalOdds: parseFloat(calculatedOdds.toFixed(2)),
                 recommendedStake: stake,
                 confidenceScore: parseFloat(p.confidenceScore) || 8.5,
                 riskLevel: p.riskLevel || 'Medium',
                 expectedValue: parseFloat(p.expectedValue) || 0,
                 stakePercentage: p.stakePercentage || 100,
                 overallReasoning: p.overallReasoning || "Strategy based on team form."
             } as ParlayRecommendation;
        });

        return results.filter(p => p.legs && p.legs.length > 0 && p.totalOdds > 1.05);
    } catch (e) {
        return [];
    }
};

export const fetchUpcomingMatches = async (settings: UserSettings): Promise<{ matches: MatchData[], rawContext: string }> => {
  try {
    const model = 'gemini-3-flash-preview';
    const date = settings.targetDate;
    const prompt = `Search for professional football fixtures on ${date}. Global Scan: ${settings.isGlobalScan}. Provide odds and recent form.`;

    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: { tools: [{ googleSearch: {} }] },
    });

    const rawText = response.text || "";

    const formattingPrompt = `Extract football matches for ${date} from: ${rawText}. Return JSON array of MatchData.`;
    const formatResponse = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: formattingPrompt,
      config: { responseMimeType: 'application/json' }
    });

    let parsedMatches = JSON.parse(cleanJson(formatResponse.text || "[]"));
    return { matches: Array.isArray(parsedMatches) ? parsedMatches : [], rawContext: rawText };
  } catch (error) {
    throw new Error("Search grounding failed.");
  }
};

export const analyzeAndGenerateParlays = async (
  matchesContext: string,
