export const generateStrategyPlan = async (settings: UserSettings, matchesContext: string): Promise<StrategyPlan> => {
  try {
    const model = 'gemini-3-pro-preview';
    const prompt = `
      Act as a Sports Investment Strategist. Create a "Ladder" strategy.
      Starting: $${settings.bankroll}
      Target: $${settings.targetBankroll}
      Target Odds per Step: ${settings.targetOdds}

      MATCH CONTEXT FOR STEP 1:
      ${matchesContext}

      TASK:
      1. Calculate how many steps of ${settings.targetOdds} odds (all-in compounding) it takes to reach $${settings.targetBankroll}.
      2. For STEP 1, use the provided matches to create a real ParlayRecommendation.
      3. For future steps, create placeholders with dates and a suggested league to target.

      Return a JSON object matching the StrategyPlan interface:
      {
        "createdAt": "string",
        "startingBankroll": number,
        "targetBankroll": number,
        "targetOdds": number,
        "totalSteps": number,
        "analysis": "string summary",
        "steps": [{
           "stepNumber": number,
           "date": "string",
           "plannedStake": number,
           "projectedWin": number,
           "note": "string",
           "parlayRecommendation": { ... } // Only for step 1
        }]
      }
    `;

    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: { 
        thinkingConfig: { thinkingBudget: 16000 },
        responseMimeType: 'application/json' 
      },
    });

    const result = JSON.parse(cleanJson(response.text || "{}"));
    return {
      ...result,
      steps: Array.isArray(result.steps) ? result.steps : []
    };
  } catch (e) {
    return {
      createdAt: new Date().toISOString(),
      startingBankroll: settings.bankroll,
      targetBankroll: settings.targetBankroll,
      targetOdds: settings.targetOdds,
      totalSteps: 1,
      analysis: "Failed to generate plan. Please try again.",
      steps: []
    };
  }
};

export const performBacktest = async (settings: UserSettings): Promise<BacktestResult> => {
  const model = 'gemini-3-pro-preview';
  const dateToTest = settings.backtestDate || settings.targetDate;
  const prompt = `Conduct a historical banker simulation for ${dateToTest} aiming for ${settings.targetOdds} odds. Use Google Search. Return JSON.`;
  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: { tools: [{ googleSearch: {} }], thinkingConfig: { thinkingBudget: 16000 }, responseMimeType: 'application/json' },
  });
  const result = JSON.parse(cleanJson(response.text || "{}"));
  return {
    ...result,
    trades: Array.isArray(result.trades) ? result.trades : []
  };
};

export const generateBetslipOfTheWeek = analyzeAndGenerateParlays;
export const generateOneShotParlay = analyzeAndGenerateParlays;
export const generateCorrectScoreTips = analyzeAndGenerateParlays;
