import React, { useState } from 'react';
import { AppState, UserSettings, MatchData, ParlayRecommendation, BacktestResult, StrategyPlan } from './types';
import { SetupForm } from './components/SetupForm';
import { ParlayCard } from './components/ParlayCard';
import { BacktestDashboard } from './components/BacktestDashboard';
import { StrategyDashboard } from './components/StrategyDashboard';
import { LoadingScreen } from './components/LoadingScreen';
import { fetchUpcomingMatches, analyzeAndGenerateParlays, performBacktest, generateStrategyPlan, generateBetslipOfTheWeek, generateOneShotParlay, performOneShotBacktest, generateCorrectScoreTips, getMarketSummary } from './services/geminiService';
import { ShieldAlert, Settings2, Globe, Zap, Coffee, Info } from 'lucide-react';

export default function App() {
  const [state, setState] = useState<AppState>('setup');
  const [settings, setSettings] = useState<UserSettings | null>(null);
  const [matches, setMatches] = useState<MatchData[]>([]);
  const [parlays, setParlays] = useState<ParlayRecommendation[]>([]);
  const [backtestResults, setBacktestResults] = useState<BacktestResult | null>(null);
  const [strategyPlan, setStrategyPlan] = useState<StrategyPlan | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [scoutAdvice, setScoutAdvice] = useState<string | null>(null);

  const handleSetupComplete = async (userSettings: UserSettings) => {
    setSettings(userSettings);
    setError(null);
    setScoutAdvice(null);

    try {
      if (userSettings.analysisMode === 'live' || 
          userSettings.analysisMode === 'betslip_of_the_week' || 
          userSettings.analysisMode === 'one_shot_challenge' || 
          userSettings.analysisMode === 'correct_score') {

        setState('searching');
        const { matches: foundMatches, rawContext } = await fetchUpcomingMatches(userSettings);
        setMatches(foundMatches);

        if (!foundMatches || foundMatches.length === 0) {
          const advice = await getMarketSummary(userSettings);
          setScoutAdvice(advice);
          setState('error');
          return;
        }

        setState('analyzing');
        let recommendations: ParlayRecommendation[] = [];

        switch(userSettings.analysisMode) {
          case 'live': recommendations = await analyzeAndGenerateParlays(rawContext, userSettings); break;
          case 'betslip_of_the_week': recommendations = await generateBetslipOfTheWeek(rawContext, userSettings); break;
          case 'one_shot_challenge': recommendations = await generateOneShotParlay(rawContext, userSettings); break;
          case 'correct_score': recommendations = await generateCorrectScoreTips(rawContext, userSettings); break;
        }

        if (recommendations.length === 0) {
          const advice = await getMarketSummary(userSettings);
          setScoutAdvice(advice);
          setState('error');
          return;
        }

        setParlays(recommendations);
        setState('results');

      } else if (userSettings.analysisMode === 'strategy_prep') {
        setState('searching'); 
        const { matches: foundMatches, rawContext } = await fetchUpcomingMatches(userSettings);
        setState('analyzing');
        const plan = await generateStrategyPlan(userSettings, rawContext);
        setStrategyPlan(plan);
        setState('strategy_results');

      } else {
        setState('backtesting');
        const results = userSettings.analysisMode === 'one_shot_backtest' 
          ? await performOneShotBacktest(userSettings)
          : await performBacktest(userSettings);
        setBacktestResults(results);
        setState('backtest_results');
      }

    } catch (err) {
      setError("Market data temporarily unavailable. Please try a different date or expand scan depth.");
      setState('error');
    }
  };

  const handleReset = () => {
    setState('setup');
    setSettings(null);
    setMatches([]);
    setParlays([]);
    setBacktestResults(null);
    setStrategyPlan(null);
    setScoutAdvice(null);
  };

  return (
    <div className="min-h-screen bg-slate-900 flex flex-col">
      <header className="bg-slate-900 border-b border-slate-800 sticky top-0 z-50 backdrop-blur-md bg-opacity-80">
        <div className="max-w-7xl mx-auto px-4 py-4 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-lg shadow-lg shadow-indigo-500/20">
              <Globe className="text-white" size={24} />
            </div>
            <div>
              <h1 className="text-xl font-bold text-white tracking-tight">SmartBet Analytics</h1>
              <span className="text-xs text-indigo-400 font-mono uppercase tracking-widest">Global Scan Engine</span>
            </div>
          </div>
          {(state !== 'setup' && state !== 'searching' && state !== 'analyzing' && state !== 'backtesting') && (
            <button onClick={handleReset} className="flex items-center gap-2 text-sm text-slate-400 hover:text-white transition-colors bg-slate-800 px-3 py-1.5 rounded-lg border border-slate-700">
              <Settings2 size={16} /> Configuration
            </button>
          )}
        </div>
      </header>

      <main className="flex-grow p-4 md:p-8">
        <div className="max-w-7xl mx-auto">
          {state === 'setup' && <div className="mt-8 animate-in fade-in zoom-in duration-500"><SetupForm onComplete={handleSetupComplete} /></div>}
          {(state === 'searching' || state === 'analyzing' || state === 'backtesting') && <div className="mt-12"><LoadingScreen stage={state === 'searching' ? 'searching' : 'analyzing'} /></div>}

          {state === 'error' && (
            <div className="mt-12 text-center max-w-xl mx-auto animate-in slide-in-from-bottom-4">
              <div className="bg-slate-800 p-10 rounded-3xl border border-slate-700 shadow-2xl">
                <div className="inline-flex bg-amber-500/10 p-6 rounded-full mb-6 border border-amber-500/20">
                  <Coffee className="text-amber-400" size={48} />
                </div>
                <h2 className="text-3xl font-bold text-white mb-4">A Professional Skip</h2>

                <div className="bg-slate-900/80 border-l-4 border-amber-500 p-6 text-left mb-8 rounded-r-xl">
                   <div className="flex items-center gap-2 text-amber-400 font-bold uppercase tracking-widest text-xs mb-3">
                      <Info size={14} /> Scout's Report for {settings?.targetDate}
                   </div>
                   <p className="text-slate-300 leading-relaxed italic">
                    "{scoutAdvice || error || "Today doesn't offer the high-confidence 'Banker' opportunities we look for. Forcing a bet in a quiet market is the fastest way to drain a bankroll."}"
                   </p>
                </div>

                <p className="text-slate-500 text-sm mb-10 max-w-md mx-auto">
                  Disciplined betting means knowing when to stay on the sidelines. We recommend checking another date with more high-volume league fixtures.
                </p>

                <div className="flex flex-col sm:flex-row gap-4">
                   <button 
                    onClick={handleReset} 
                    className="flex-1 bg-indigo-600 hover:bg-indigo-500 text-white px-8 py-4 rounded-2xl font-bold transition-all flex items-center justify-center gap-2 shadow-lg shadow-indigo-600/20"
                  >
                    Check Another Date <Zap size={18} />
                  </button>
                </div>
              </div>
            </div>
          )}

          {state === 'results' && (
            <div className="space-y-8 animate-in fade-in duration-700">
              <div className="bg-slate-800/80 border border-slate-700 rounded-2xl p-6 flex flex-wrap items-center justify-between gap-6 shadow-xl backdrop-blur-sm">
                 <div className="flex items-center gap-4 text-slate-300">
                    <div className="bg-indigo-600/20 p-3 rounded-xl border border-indigo-500/30 text-indigo-400">
                      <Globe size={24} />
                    </div>
                    <div>
                        <div className="text-xs text-slate-500 uppercase font-bold tracking-widest mb-1">Active Scenario</div>
                        <div className="text-lg font-bold text-white">
                          {settings?.isGlobalScan ? 'World-Wide Search' : 'Multi-League Target'}
                          <span className="mx-2 text-slate-600">/</span>
                          <span className="text-indigo-400">{settings?.targetDate}</span>
                        </div>
                    </div>
                 </div>
                 <div className="flex gap-8 items-center">
                    <div className="text-center">
                      <div className="text-[10px] text-slate-500 uppercase font-bold tracking-widest mb-1">Current Bankroll</div>
                      <div className="text-xl font-mono text-emerald-400 font-bold">${settings?.bankroll}</div>
                    </div>
                    <div className="w-px h-8 bg-slate-700"></div>
                    <div className="text-center">
                      <div className="text-[10px] text-slate-500 uppercase font-bold tracking-widest mb-1">Target Outcome</div>
                      <div className="text-xl font-mono text-yellow-400 font-bold">${settings?.targetBankroll}</div>
                    </div>
                 </div>
              </div>

              <div className={`grid grid-cols-1 ${parlays.length === 1 ? 'max-w-2xl mx-auto' : 'lg:grid-cols-2 xl:grid-cols-3'} gap-8`}>
                {parlays.map((parlay, idx) => (
                  <div key={idx} className="h-full animate-in slide-in-from-bottom-8" style={{ animationDelay: `${idx * 150}ms` }}>
                    <ParlayCard parlay={parlay} />
                  </div>
                ))}
              </div>
            </div>
          )}

          {state === 'strategy_results' && strategyPlan && <StrategyDashboard plan={strategyPlan} />}
          {state === 'backtest_results' && backtestResults && <BacktestDashboard results={backtestResults} />}
        </div>
      </main>

      <footer className="bg-slate-900/50 border-t border-slate-800 py-10 mt-auto">
        <div className="max-w-4xl mx-auto px-4 text-center">
          <div className="flex items-center justify-center gap-2 text-rose-500 font-bold mb-3 uppercase tracking-widest text-xs">
            <ShieldAlert size={14} /> Risk Disclaimer
          </div>
          <p className="text-slate-500 text-[10px] leading-relaxed max-w-2xl mx-auto uppercase tracking-tighter">
            SmartBet uses Gemini 3.0 Pro grounding to analyze live professional sports data. All projections are statistical probabilities. 
            compounding 100% bankroll is a high-risk strategy. 18+ Only.
          </p>
        </div>
      </footer>
    </div>
  );
}

