function generateFallbackSteps(settings: UserSettings, count: number): StrategyStep[] {
  const steps: StrategyStep[] = [];
  let currentStake = settings.bankroll;
  for (let i = 1; i <= count; i++) {
    const win = currentStake * settings.targetOdds;
    steps.push({
      stepNumber: i,
      date: `Step ${i} Window`,
      plannedStake: currentStake,
      projectedWin: win,
      status: i === 1 ? 'ready' : 'pending_previous_win',
      note: `Target ${settings.targetOdds} odds selection.`
    });
    currentStake = win;
  }
  return steps;
}

