                 GOAL REACHED
              </div>
            ) : isBust ? (
              <div className="px-4 py-2 rounded-lg font-black text-xs flex items-center gap-2 bg-rose-500/20 text-rose-400 border border-rose-500/30 uppercase tracking-widest">
